// app/shell.tsx
"use client";

import * as React from "react";
import {Box, Container} from "@mui/material";
import {usePathname} from "next/navigation";
import Header from "./components/Header"; // Breadcrumb/หรือ Header ที่คุณทำไว้
import SideMenu from "./components/SideMenu"; // เวอร์ชันคอมแพ็คที่ปรับไว้
import AppBreadCrumb from "./components/AppBreadCrumb";

export default function AppShell({children}: {children: React.ReactNode}) {
	const [openMobile, setOpenMobile] = React.useState(false);
	const pathname = usePathname();

	return (
		<>
			<Header onMenuClick={() => setOpenMobile(true)} />
			<Box
				sx={{
					display: "flex",
					minHeight: "100dvh",
					bgcolor: "background.default",
				}}
			>
				<SideMenu currentPath={pathname ?? "/"} />
				<Box component="main" sx={{ flex: 1, mt: { xs: '64px', md: 0 }, px: { xs: 2, md: 3 } }}>
        <Container maxWidth="lg">
          <AppBreadcrumb />     {/* ✅ Breadcrumb อยู่ใน container เดียวกับ content */}
          {children}            {/* ✅ Content ต่าง ๆ เช่น Chart, Table ฯลฯ */}
        </Container>
      </Box>
			</Box>
		</>
	);
}
